  position: sticky;
  top: 0;
}

/* Style the header differently once it sticks */
@container scroll-state(stuck: top) {
  .sticky-header {
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    background: rgba(255, 255, 255, 0.9);
    backdrop-filter: blur(8px);
  }
}
```

When the header sticks to the top, you get a shadow + frosted-glass effect—no JS required.

