  <foreignObject width="100%" height="100%">${html}</foreignObject>
</svg>`;

const img = new Image();
img.onload = () => ctx.drawImage(img, 0, 0);
img.src = 'data:image/svg+xml;charset=utf-8,' + encodeURIComponent(svg);
